{
  "name": "LF - Personal Trainer",
  "description": "Aplicativo oficial do Personal Trainer Lucas França. Treinos de alta performance, nutrição e gestão de agenda."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum View {
  DASHBOARD = 'DASHBOARD',
  WORKOUTS = 'WORKOUTS',
  SCHEDULE = 'SCHEDULE',
  NUTRITION = 'NUTRITION',
  PROFILE = 'PROFILE'
}

export interface WorkoutPlan {
  id: string;
  title: string;
  subtitle: string;
  duration: string;
  kcal: number;
  image: string;
  tags: string[];
}

export interface ClassSession {
  id: string;
  time: string;
  period: 'Manhã' | 'Tarde' | 'Noite';
  title: string;
  instructor: string;
  spots: number;
  totalSpots: number;
  booked: boolean;
}

export interface NutritionTip {
  id: string;
  category: string;
  title: string;
  desc: string;
  image: string;
}

export interface UserStats {
  workouts: number;
  kcal: number;
  minutes: number;
}

import React, { useState } from 'react';
import { View } from './types';
import Dashboard from './components/pages/Dashboard';
import Workouts from './components/pages/Workouts';
import Schedule from './components/pages/Schedule';
import Nutrition from './components/pages/Nutrition';
import Profile from './components/pages/Profile';
import BottomNav from './components/layout/BottomNav';
import Header from './components/layout/Header';
import { MessageCircle } from 'lucide-react';

export default function App() {
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);

  const renderView = () => {
    switch (currentView) {
      case View.DASHBOARD:
        return <Dashboard onViewChange={setCurrentView} />;
      case View.WORKOUTS:
        return <Workouts />;
      case View.SCHEDULE:
        return <Schedule />;
      case View.NUTRITION:
        return <Nutrition />;
      case View.PROFILE:
        return <Profile />;
      default:
        return <Dashboard onViewChange={setCurrentView} />;
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-lf-black text-white pb-24 relative max-w-md mx-auto shadow-2xl shadow-lf-dark/50 border-x border-white/5">
      {/* Fixed Header */}
      <Header currentView={currentView} />

      {/* Scrollable Content */}
      <main className="flex-1 overflow-y-auto pt-4">
        {renderView()}
      </main>

      {/* Floating WhatsApp Button (Sticky) */}
      <a 
        href="https://wa.me/" 
        target="_blank" 
        rel="noopener noreferrer"
        className="fixed bottom-24 right-4 md:right-[calc(50%-12rem+1rem)] z-50 bg-lf-navy text-white p-4 rounded-full shadow-lg shadow-lf-neon/20 hover:scale-110 transition-transform border border-white/10"
        aria-label="Falar com Lucas França"
      >
        <MessageCircle className="w-6 h-6" />
      </a>

      {/* Fixed Bottom Navigation */}
      <BottomNav currentView={currentView} onViewChange={setCurrentView} />
    </div>
  );
}

import React from 'react';
import { Bell, User } from 'lucide-react';
import { View } from '../../types';

interface HeaderProps {
  currentView: View;
}

const Header: React.FC<HeaderProps> = ({ currentView }) => {
  const getTitle = () => {
    switch (currentView) {
      case View.DASHBOARD: return 'LF Personal';
      case View.WORKOUTS: return 'Hub de Treinos';
      case View.SCHEDULE: return 'Agenda';
      case View.NUTRITION: return 'Nutrição VIP';
      case View.PROFILE: return 'Meu Perfil';
      default: return 'LF Personal';
    }
  };

  return (
    <header className="sticky top-0 z-40 bg-lf-black/80 backdrop-blur-md border-b border-white/5 px-6 py-4 flex items-center justify-between">
      <div className="flex items-center gap-3">
        {currentView === View.DASHBOARD ? (
          <div className="w-10 h-10 bg-lf-neon rounded-lg flex items-center justify-center shadow-[0_0_15px_rgba(230,255,0,0.3)]">
            <span className="font-display font-bold text-lf-black text-xl tracking-tighter">LF</span>
          </div>
        ) : null}
        <div className="flex flex-col">
          {currentView === View.DASHBOARD && (
            <span className="text-[10px] text-lf-neon font-bold tracking-[0.2em] uppercase">Metodologia</span>
          )}
          <h1 className="text-xl font-display font-bold tracking-tight text-white">{getTitle()}</h1>
        </div>
      </div>

      <div className="flex items-center gap-4">
        <button className="relative text-gray-400 hover:text-white transition-colors">
          <Bell className="w-6 h-6" />
          <span className="absolute top-0 right-0 w-2 h-2 bg-lf-neon rounded-full"></span>
        </button>
        <div className="w-10 h-10 rounded-full border-2 border-lf-neon/30 p-0.5 overflow-hidden">
          <img 
            src="https://picsum.photos/seed/lucas/200/200" 
            alt="Profile" 
            className="w-full h-full object-cover rounded-full"
          />
        </div>
      </div>
    </header>
  );
};

export default Header;

import React from 'react';
import { Home, Dumbbell, Calendar, Apple, User } from 'lucide-react';
import { View } from '../../types';

interface BottomNavProps {
  currentView: View;
  onViewChange: (view: View) => void;
}

const BottomNav: React.FC<BottomNavProps> = ({ currentView, onViewChange }) => {
  const navItems = [
    { id: View.DASHBOARD, icon: Home, label: 'Início' },
    { id: View.WORKOUTS, icon: Dumbbell, label: 'Treinos' },
    { id: View.SCHEDULE, icon: Calendar, label: 'Agenda' },
    { id: View.NUTRITION, icon: Apple, label: 'Nutrição' },
    { id: View.PROFILE, icon: User, label: 'Perfil' },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 z-50 bg-lf-black/95 backdrop-blur-xl border-t border-white/5 max-w-md mx-auto">
      <div className="flex justify-between items-center px-6 py-4">
        {navItems.map((item) => {
          const isActive = currentView === item.id;
          return (
            <button
              key={item.id}
              onClick={() => onViewChange(item.id)}
              className={`flex flex-col items-center gap-1 group transition-all duration-300 ${
                isActive ? 'text-lf-neon -translate-y-1' : 'text-gray-500 hover:text-gray-300'
              }`}
            >
              <item.icon 
                className={`w-6 h-6 transition-transform ${isActive ? 'scale-110 stroke-[2.5px]' : ''}`} 
              />
              <span className="text-[10px] font-bold uppercase tracking-wider">
                {item.label}
              </span>
              {isActive && (
                <span className="absolute -bottom-2 w-1 h-1 bg-lf-neon rounded-full shadow-[0_0_8px_#E6FF00]"></span>
              )}
            </button>
          );
        })}
      </div>
    </nav>
  );
};

export default BottomNav;

import React, { useState } from 'react';
import { Calendar as CalendarIcon, ChevronLeft, ChevronRight, CheckCircle2, Clock, MapPin } from 'lucide-react';
import { ClassSession } from '../../types';

const Schedule: React.FC = () => {
  const [selectedDate, setSelectedDate] = useState(5);
  const [filter, setFilter] = useState<'individual' | 'group'>('group');

  const days = [
    { day: 'SEG', date: 2 },
    { day: 'TER', date: 3 },
    { day: 'QUA', date: 4 },
    { day: 'QUI', date: 5 },
    { day: 'SEX', date: 6 },
    { day: 'SÁB', date: 7 },
  ];

  const classes: ClassSession[] = [
    {
      id: '1',
      time: '07:00',
      period: 'Manhã',
      title: 'Cross-Training Elite',
      instructor: 'Lucas Ferreira',
      spots: 4,
      totalSpots: 12,
      booked: false
    },
    {
      id: '2',
      time: '09:00',
      period: 'Manhã',
      title: 'HIIT Burn Intenso',
      instructor: 'Amanda Silva',
      spots: 1,
      totalSpots: 15,
      booked: false
    },
    {
      id: '3',
      time: '18:30',
      period: 'Noite',
      title: 'Funcional Ativo',
      instructor: 'Lucas Ferreira',
      spots: 0,
      totalSpots: 12,
      booked: true
    }
  ];

  const toggleBooking = (id: string) => {
    // Logic to toggle booking would go here
    console.log(`Toggling booking for class ${id}`);
  };

  return (
    <div className="px-6 space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">

      {/* Calendar Strip */}
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <h2 className="text-sm font-bold text-gray-400 uppercase tracking-widest">Outubro 2023</h2>
          <div className="flex gap-2 text-gray-400">
            <ChevronLeft className="w-5 h-5 cursor-pointer hover:text-white" />
            <ChevronRight className="w-5 h-5 cursor-pointer hover:text-white" />
          </div>
        </div>

        <div className="flex justify-between gap-2 overflow-x-auto pb-2 scrollbar-hide">
          {days.map((d) => {
            const isSelected = selectedDate === d.date;
            return (
              <button
                key={d.date}
                onClick={() => setSelectedDate(d.date)}
                className={`flex flex-col items-center min-w-[50px] p-2 rounded-xl border transition-all duration-300 ${
                  isSelected 
                    ? 'bg-lf-neon border-lf-neon text-lf-black shadow-[0_0_15px_rgba(230,255,0,0.4)]' 
                    : 'bg-lf-navy/30 border-white/5 text-gray-400 hover:bg-lf-navy/50'
                }`}
              >
                <span className="text-[10px] font-bold uppercase mb-1">{d.day}</span>
                <span className="text-xl font-display font-bold">{String(d.date).padStart(2, '0')}</span>
              </button>
            );
          })}
        </div>
      </div>

      {/* Filter Toggles */}
      <div className="bg-lf-navy/30 p-1 rounded-xl flex border border-white/5">
        <button
          onClick={() => setFilter('individual')}
          className={`flex-1 py-2 text-xs font-bold uppercase rounded-lg transition-colors ${
            filter === 'individual' ? 'bg-lf-neon text-lf-black' : 'text-gray-400 hover:text-white'
          }`}
        >
          Individual
        </button>
        <button
          onClick={() => setFilter('group')}
          className={`flex-1 py-2 text-xs font-bold uppercase rounded-lg transition-colors ${
            filter === 'group' ? 'bg-lf-neon text-lf-black' : 'text-gray-400 hover:text-white'
          }`}
        >
          Aulas Coletivas
        </button>
      </div>

      {/* Class List */}
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="text-lg font-bold font-display text-white">Aulas Disponíveis</h3>
          <span className="text-[10px] bg-lf-neon/10 text-lf-neon border border-lf-neon/20 px-2 py-1 rounded uppercase font-bold">Hoje</span>
        </div>

        {classes.map((cls) => {
          const isFull = cls.spots === 0;
          const isLastSpots = cls.spots > 0 && cls.spots <= 3;

          return (
            <div 
              key={cls.id}
              className={`relative overflow-hidden rounded-xl border p-5 transition-all ${
                cls.booked 
                  ? 'bg-lf-navy/20 border-lf-neon/30' 
                  : isFull 
                    ? 'bg-lf-dark/50 border-white/5 opacity-60' 
                    : 'bg-lf-navy/40 border-white/10 hover:border-lf-neon/50'
              }`}
            >
              {isLastSpots && !cls.booked && (
                <div className="absolute top-0 right-0 p-2">
                  <span className="text-[9px] bg-red-500 text-white px-2 py-0.5 rounded-full font-bold animate-pulse">
                    Últimas Vagas
                  </span>
                </div>
              )}

              <div className="flex justify-between items-start mb-4">
                <div className="space-y-1">
                  <div className="flex items-center gap-2 text-lf-neon">
                    <Clock className="w-4 h-4" />
                    <span className="text-sm font-bold text-white">{cls.time}</span>
                  </div>
                  <h4 className="text-lg font-display font-bold uppercase tracking-wide">{cls.title}</h4>
                  <p className="text-xs text-gray-400">Prof. {cls.instructor}</p>
                </div>

                {!cls.booked && (
                  <div className={`text-right text-[10px] font-bold uppercase border px-2 py-1 rounded ${
                    isFull ? 'text-gray-500 border-gray-700' : 'text-lf-neon border-lf-neon/30'
                  }`}>
                     Vagas: {cls.spots}/{cls.totalSpots}
                  </div>
                )}
              </div>

              <button
                disabled={isFull && !cls.booked}
                onClick={() => toggleBooking(cls.id)}
                className={`w-full py-3 rounded-lg font-bold text-sm uppercase flex items-center justify-center gap-2 transition-all ${
                  cls.booked
                    ? 'bg-transparent text-lf-neon border border-lf-neon'
                    : isFull
                      ? 'bg-white/5 text-gray-500 cursor-not-allowed'
                      : 'bg-lf-neon text-lf-black hover:bg-white hover:scale-[1.02]'
                }`}
              >
                {cls.booked ? (
                  <>
                    <CheckCircle2 className="w-4 h-4" /> Confirmado
                  </>
                ) : isFull ? (
                  'Lotado'
                ) : (
                  'Fazer Check-in'
                )}
              </button>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Schedule;

import React, { useState } from 'react';
import { Droplets, Utensils, ChevronRight, Info } from 'lucide-react';

const Nutrition: React.FC = () => {
  const [waterIntake, setWaterIntake] = useState(1.2);
  const waterGoal = 2.8;

  const addWater = () => {
    setWaterIntake(prev => Math.min(prev + 0.25, waterGoal));
  };

  const recipes = [
    {
      title: 'Frango Grelhado com Ervas',
      tags: ['Proteico', 'Low Carb'],
      time: '25 min',
      kcal: 320,
      img: 'https://images.unsplash.com/photo-1532550907401-a500c9a57435?q=80&w=1469&auto=format&fit=crop'
    },
    {
      title: 'Bowl de Açaí Proteico',
      tags: ['Pós-Treino', 'Energético'],
      time: '10 min',
      kcal: 450,
      img: 'https://images.unsplash.com/photo-1590301157890-4810ed352733?q=80&w=1336&auto=format&fit=crop'
    }
  ];

  return (
    <div className="px-6 space-y-8 animate-in fade-in duration-500">

      {/* Hydration Card */}
      <section className="bg-lf-dark border border-white/5 rounded-2xl p-6 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-10">
          <Droplets className="w-32 h-32 text-blue-500" />
        </div>

        <h2 className="text-xl font-display font-bold text-white mb-1">Hidratação</h2>
        <p className="text-gray-400 text-xs mb-6">Mantenha sua performance no auge.</p>

        <div className="flex items-end gap-2 mb-2">
           <span className="text-4xl font-display font-bold text-white">{waterIntake.toFixed(1)}</span>
           <span className="text-sm text-gray-400 mb-2">/ {waterGoal} Litros</span>
        </div>

        {/* Progress Bar */}
        <div className="w-full bg-lf-navy/30 rounded-full h-3 mb-6 relative overflow-hidden">
          <div 
            className="absolute top-0 left-0 h-full bg-blue-500 rounded-full transition-all duration-500 ease-out"
            style={{ width: `${(waterIntake / waterGoal) * 100}%` }}
          ></div>
        </div>

        <button 
          onClick={addWater}
          className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-3 rounded-xl flex items-center justify-center gap-2 transition-colors uppercase text-xs tracking-wider"
        >
          <Droplets className="w-4 h-4" /> Registrar +250ml
        </button>
      </section>

      {/* Tips Carousel */}
      <section>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-bold font-display">Dicas Estratégicas</h2>
          <span className="text-xs text-lf-neon cursor-pointer hover:underline">Ver todas</span>
        </div>

        <div className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide">
           {[
             { title: 'Pré-Treino: Energia', desc: 'Carboidratos de rápida absorção 30min antes.', label: 'Desempenho' },
             { title: 'Pós-Treino: Recuperação', desc: 'Whey + Fruta na janela anabólica.', label: 'Recuperação' },
             { title: 'Sono Profundo', desc: 'Magnésio e zero telas 1h antes de dormir.', label: 'Biohack' },
           ].map((tip, idx) => (
             <div key={idx} className="min-w-[200px] bg-lf-navy/20 border border-white/5 p-4 rounded-xl flex flex-col justify-between h-40 group hover:border-lf-neon/30 transition-colors">
                <div>
                  <span className="inline-block px-2 py-0.5 bg-lf-neon/10 text-lf-neon text-[9px] font-bold uppercase rounded mb-2">
                    {tip.label}
                  </span>
                  <h3 className="font-bold text-white leading-tight mb-2">{tip.title}</h3>
                  <p className="text-xs text-gray-400 leading-relaxed">{tip.desc}</p>
                </div>
                <div className="flex justify-end">
                   <div className="w-6 h-6 rounded-full bg-white/5 flex items-center justify-center group-hover:bg-lf-neon group-hover:text-black transition-colors">
                     <ChevronRight className="w-3 h-3" />
                   </div>
                </div>
             </div>
           ))}
        </div>
      </section>

      {/* Recipes */}
      <section>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-bold font-display">Receitas Exclusivas</h2>
          <Utensils className="w-5 h-5 text-gray-500" />
        </div>

        <div className="space-y-4">
          {recipes.map((recipe, idx) => (
            <div key={idx} className="bg-lf-dark rounded-xl overflow-hidden border border-white/5 flex group cursor-pointer hover:border-lf-neon/30 transition-colors">
               <div className="w-1/3 relative">
                 <img src={recipe.img} alt={recipe.title} className="w-full h-full object-cover" />
