                 <div className="flex items-center gap-4 text-xs text-gray-400 font-mono">
                   <span>{recipe.time}</span>
                   <span>{recipe.kcal} kcal</span>
                 </div>
               </div>
            </div>
          ))}
        </div>
      </section>

    </div>
  );
};

export default Nutrition;

