import React, { useState } from 'react';
import { View, User } from './types';
import Dashboard from './components/pages/Dashboard';
import Workouts from './components/pages/Workouts';
import Schedule from './components/pages/Schedule';
import Nutrition from './components/pages/Nutrition';
import Profile from './components/pages/Profile';
import Login from './components/pages/Login';
import BottomNav from './components/layout/BottomNav';
import Header from './components/layout/Header';
import { MessageCircle } from 'lucide-react';

export default function App() {
  const [currentView, setCurrentView] = useState<View>(View.LOGIN);
  const [user, setUser] = useState<User | null>(null);

  const handleLogin = (userData: User) => {
    setUser(userData);
    setCurrentView(View.DASHBOARD);
  };

  const renderView = () => {
    switch (currentView) {
      case View.LOGIN:
        return <Login onLogin={handleLogin} />;
      case View.DASHBOARD:
        return <Dashboard onViewChange={setCurrentView} user={user} />;
      case View.WORKOUTS:
        return <Workouts onViewChange={setCurrentView} />;
      case View.SCHEDULE:
        return <Schedule />;
      case View.NUTRITION:
        return <Nutrition />;
      case View.PROFILE:
        return <Profile user={user} />;
      default:
        return <Dashboard onViewChange={setCurrentView} user={user} />;
    }
  };

  if (currentView === View.LOGIN) {
    return renderView();
  }

  return (
    <div className="flex flex-col min-h-screen bg-lf-black text-white pb-24 relative max-w-md mx-auto shadow-2xl shadow-lf-dark/50 border-x border-white/5">
      {/* Fixed Header */}
      <Header currentView={currentView} user={user} />

      {/* Scrollable Content */}
      <main className="flex-1 overflow-y-auto pt-4 no-scrollbar">
        {renderView()}
      </main>

      {/* Floating WhatsApp Button (Sticky) */}
      <a 
        href="https://wa.me/" 
        target="_blank" 
        rel="noopener noreferrer"
        className="fixed bottom-24 right-4 md:right-[calc(50%-12rem+1rem)] z-50 bg-lf-navy text-white p-4 rounded-full shadow-lg shadow-lf-neon/20 hover:scale-110 transition-transform border border-white/10"
        aria-label="Falar com Lucas França"
      >
        <MessageCircle className="w-6 h-6" />
      </a>

      {/* Fixed Bottom Navigation */}
      <BottomNav currentView={currentView} onViewChange={setCurrentView} />
    </div>
  );
}

