import React, { useState } from 'react';
import { User, View } from '../../types';
import { ArrowRight, Lock, Mail, User as UserIcon } from 'lucide-react';

interface LoginProps {
  onLogin: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    // Simulate API Call
    setTimeout(() => {
      onLogin({
        name: isRegistering ? name : 'Carlos Oliveira',
        email: email,
        // Tradução dos dados do usuário simulado
        level: isRegistering ? 'Iniciante' : 'Atleta Avançado',
        since: isRegistering ? 'Out 2023' : 'Jan 2023',
        // Placeholder for student photo
        photo: 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=200&auto=format&fit=crop'
      });
    }, 1500);
  };

  return (
    <div className="h-full bg-white dark:bg-lf-black flex flex-col justify-center px-6 relative overflow-hidden transition-colors duration-500">
      {/* Background Ambience */}
      <div className="absolute top-0 left-0 w-full h-1/2 bg-gradient-to-b from-lf-navy/10 dark:from-lf-navy/40 to-transparent z-0"></div>
      <div className="absolute -top-20 -right-20 w-64 h-64 bg-lf-navy/10 dark:bg-lf-neon/10 rounded-full blur-3xl"></div>

      <div className="relative z-10 w-full max-w-sm mx-auto space-y-8">

        {/* Logo Section */}
        <div className="flex flex-col items-center animate-in fade-in slide-in-from-top-4 duration-700">
           <div className="w-20 h-20 bg-lf-navy dark:bg-lf-neon rounded-2xl flex items-center justify-center shadow-lg dark:shadow-[0_0_30px_rgba(230,255,0,0.4)] mb-6 transform rotate-3">
            <span className="font-display font-black text-white dark:text-lf-black text-4xl tracking-tighter">LF</span>
          </div>
          <h1 className="text-3xl font-display font-bold text-gray-900 dark:text-white text-center">
            Lucas França<br/>
            <span className="text-lf-navy dark:text-lf-neon text-lg tracking-[0.3em] font-medium uppercase">Personal Trainer</span>
          </h1>
        </div>

        {/* Form Container */}
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700 delay-150">
          <div className="text-center">
            <h2 className="text-gray-900 dark:text-white font-bold text-xl mb-1">
              {isRegistering ? 'Crie sua conta' : 'Acesse seu painel'}
            </h2>
            <p className="text-gray-500 dark:text-gray-400 text-xs">
              {isRegistering ? 'Comece sua transformação hoje.' : 'Bem-vindo de volta, atleta.'}
            </p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            {isRegistering && (
              <div className="relative group animate-in slide-in-from-left-2 duration-300">
                <UserIcon className="absolute left-3 top-3.5 w-5 h-5 text-gray-400 dark:text-gray-500 group-focus-within:text-lf-navy dark:group-focus-within:text-lf-neon transition-colors" />
                <input 
                  type="text" 
                  placeholder="Seu nome completo"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full bg-gray-100 dark:bg-lf-dark/50 border border-gray-200 dark:border-white/10 rounded-xl py-3 pl-10 pr-4 text-gray-900 dark:text-white focus:outline-none focus:border-lf-navy dark:focus:border-lf-neon focus:ring-1 focus:ring-lf-navy dark:focus:ring-lf-neon transition-all placeholder:text-gray-400"
                  required={isRegistering}
                />
              </div>
            )}

            <div className="space-y-2">
              <div className="relative group">
                <Mail className="absolute left-3 top-3.5 w-5 h-5 text-gray-400 dark:text-gray-500 group-focus-within:text-lf-navy dark:group-focus-within:text-lf-neon transition-colors" />
                <input 
                  type="email" 
                  placeholder="Seu e-mail"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full bg-gray-100 dark:bg-lf-dark/50 border border-gray-200 dark:border-white/10 rounded-xl py-3 pl-10 pr-4 text-gray-900 dark:text-white focus:outline-none focus:border-lf-navy dark:focus:border-lf-neon focus:ring-1 focus:ring-lf-navy dark:focus:ring-lf-neon transition-all placeholder:text-gray-400"
                  required
                />
              </div>
              <div className="relative group">
                <Lock className="absolute left-3 top-3.5 w-5 h-5 text-gray-400 dark:text-gray-500 group-focus-within:text-lf-navy dark:group-focus-within:text-lf-neon transition-colors" />
                <input 
                  type="password" 
                  placeholder="Sua senha"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full bg-gray-100 dark:bg-lf-dark/50 border border-gray-200 dark:border-white/10 rounded-xl py-3 pl-10 pr-4 text-gray-900 dark:text-white focus:outline-none focus:border-lf-navy dark:focus:border-lf-neon focus:ring-1 focus:ring-lf-navy dark:focus:ring-lf-neon transition-all placeholder:text-gray-400"
                  required
                />
              </div>
            </div>

            <button 
              type="submit"
              disabled={isLoading}
              className="w-full bg-lf-navy dark:bg-lf-neon text-white dark:text-lf-black font-bold py-4 rounded-xl flex items-center justify-center gap-2 hover:opacity-90 transition-colors shadow-lg dark:shadow-lf-neon/20 active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed"
            >
              {isLoading ? (
                <span className="w-5 h-5 border-2 border-white dark:border-lf-black border-t-transparent rounded-full animate-spin"></span>
              ) : (
                <>
                  {isRegistering ? 'CADASTRAR' : 'ENTRAR'} <ArrowRight className="w-5 h-5" />
                </>
              )}
            </button>
          </form>

          {/* Toggle Login/Register */}
          <div className="space-y-4 text-center">
            {!isRegistering && (
              <p className="text-xs text-gray-500">
                Esqueceu sua senha? <a href="#" className="text-lf-navy dark:text-lf-neon hover:underline">Recuperar acesso</a>
              </p>
            )}

            <div className="pt-2 border-t border-gray-200 dark:border-white/5">
              <p className="text-sm text-gray-500 dark:text-gray-400">
                {isRegistering ? 'Já tem uma conta?' : 'Não tem uma conta?'}
                <button 
                  onClick={() => setIsRegistering(!isRegistering)}
                  className="ml-2 text-lf-navy dark:text-lf-neon font-bold hover:underline uppercase text-xs tracking-wider"
                >
                  {isRegistering ? 'Fazer Login' : 'Cadastre-se'}
                </button>
              </p>
            </div>
          </div>
        </div>
      </div>

      <div className="absolute bottom-6 w-full text-center left-0">
        <span className="text-[10px] text-gray-400 dark:text-gray-600 uppercase tracking-widest">Powered by LF Methodology</span>
      </div>
    </div>
  );
};

export default Login;

